solution_code:
#include <iostream>

int main() {
    std::cout << "short: "  << sizeof(short)  << " bytes, " << sizeof(short)  * 8 << " bits\n";
    std::cout << "int: "    << sizeof(int)    << " bytes, " << sizeof(int)    * 8 << " bits\n";
    std::cout << "double: " << sizeof(double) << " bytes, " << sizeof(double) * 8 << " bits\n";
    return 0;
}

